-- 1. Actualizar el perfil del ciudadano
-- Agregamos el tipo de perfil real y el modo de vista actual.
ALTER TABLE public.citizen_profiles
ADD COLUMN profile_type VARCHAR(50) DEFAULT 'local' CHECK (profile_type IN ('local', 'tourist')),
ADD COLUMN current_view_mode VARCHAR(50) DEFAULT 'local' CHECK (current_view_mode IN ('local', 'tourist'));

-- Índice para buscar rápidamente usuarios por su modo de vista (útil para analíticas)
CREATE INDEX idx_citizen_view_mode ON public.citizen_profiles(current_view_mode);

-- 2. Clasificar los Eventos
ALTER TABLE public.events
ADD COLUMN target_audience VARCHAR(50) DEFAULT 'all' CHECK (target_audience IN ('local', 'tourist', 'all'));

CREATE INDEX idx_events_audience ON public.events(target_audience);

-- 3. Clasificar las Rutas
ALTER TABLE public.routes
ADD COLUMN target_audience VARCHAR(50) DEFAULT 'all' CHECK (target_audience IN ('local', 'tourist', 'all'));

CREATE INDEX idx_routes_audience ON public.routes(target_audience);

-- 4. Clasificar las Sucursales/Lugares
ALTER TABLE public.company_branches
ADD COLUMN target_audience VARCHAR(50) DEFAULT 'all' CHECK (target_audience IN ('local', 'tourist', 'all'));

CREATE INDEX idx_branches_audience ON public.company_branches(target_audience);
